function partnersStrip() {
  const items = PARTNERS.concat(PARTNERS).map(p => `<span class="partner">${p}</span>`).join("");
  return `
<section class="section section--tight bg-2">
  <div class="container">
    <p style="text-align:center;color:var(--muted);font-family:var(--font-head);font-weight:600;font-size:.82rem;letter-spacing:.14em;text-transform:uppercase;margin-bottom:2rem" data-reveal>Pracujeme s ověřenými značkami</p>
    <div class="partners-wrap" data-reveal="80"><div class="partners">${items}</div></div>
  </div>
</section>`;
}

function serviceFeatures(items, asSteps) {
  return `
<section class="section bg-2">
  <div class="container">
    <div class="features">
      ${items.map((it, i) => `
      <div class="feature" data-reveal="${i*80}">
        ${asSteps ? `<span class="feature-step">${i + 1}</span>` : ""}
        <div class="ic-gold">${I[it.icon]}</div>
        <h3>${it.title}</h3>
        <p>${it.text}</p>
      </div>`).join("")}
    </div>
  </div>
</section>`;
}

function pageHero(base, crumbs, title, lead) {
  const cr = crumbs.map((c, i) => i < crumbs.length - 1
    ? `<a href="${c.href}">${c.label}</a> ${I.chevronR} `
    : `<span>${c.label}</span>`).join("");
  return `
<section class="page-hero">
  <div class="container">
    <nav class="breadcrumb" data-reveal>${cr}</nav>
    <h1 data-reveal="60">${title}</h1>
    <p class="lead" data-reveal="120">${lead}</p>
  </div>
</section>`;
}

/* Generic service page */
function servicePage(cfg) {
  const base = "";
  const body =
    pageHero(base, [{label:"Domů", href: base || "./"},{label:cfg.crumb}], cfg.title, cfg.lead) +
    `
<section class="section section--tight">
  <div class="container">
    <div class="split sticky-split">
      <div class="split-media sticky-col" data-reveal>
        <img src="${base}assets/img/${cfg.image}" alt="${cfg.imageAlt}" loading="lazy">
        <span class="scan"></span>
      </div>
      <div class="split-body" data-reveal="100">
        <h2>${cfg.introHeading}</h2>
        ${cfg.introBody.map(p => `<p>${p}</p>`).join("")}
        <a class="btn btn-gold" href="#poptavka" style="margin-top:1.8rem">Nezávazně poptat ${I.arrow}</a>
      </div>
    </div>
  </div>
</section>` +
    (cfg.afterIntro || "") +
    (cfg.features && cfg.features.length ? serviceFeatures(cfg.features, cfg.featuresAsSteps) : "") +
    (cfg.details ? `
<section class="section">
  <div class="container">
    ${cfg.details.map((d, i) => `
    <div class="split ${i % 2 ? "split--reverse" : ""}" style="margin-top:${i ? "clamp(3rem,6vw,5rem)" : "0"}">
      <div class="split-body" data-reveal>
        <h2>${d.heading}</h2>
        ${d.body.map(p => `<p>${p}</p>`).join("")}
        ${d.list ? `<ul class="check-list">${d.list.map(l => `<li><span class="ci">${I.check}</span><span>${l}</span></li>`).join("")}</ul>` : ""}
      </div>
      ${(d.asideHeading || d.aside) ? `<div class="aside-card" data-reveal="100">
        ${d.asideImage ? `<div class="split-media" style="margin-bottom:1.4rem;border:0"><img src="${base}assets/img/${d.asideImage}" alt="${d.asideHeading}" loading="lazy"></div>` : `<div class="ic-gold">${I[d.icon]}</div>`}
        ${d.asideHeading ? `<h3>${d.asideHeading}</h3>` : ""}
        ${d.aside ? `<p>${d.aside}</p>` : ""}
      </div>` : `<div class="split-media" data-reveal="100"><img src="${base}assets/img/${d.asideImage}" alt="${d.asideAlt || d.heading}" loading="lazy"><span class="scan"></span></div>`}
    </div>`).join("")}
  </div>
</section>` : "") +
    goldBand(base, cfg.ctaHeading, cfg.ctaText);
  return page(base, `${cfg.title} | Duo alarm`, cfg.lead, body, { ogImage: cfg.image });
}

